const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;
const username = msg.from?.username || 'User';
const firstName = msg.from?.first_name || 'User';

let command = 'chat';
let params = '';

if (text.startsWith('/')) {
  const parts = text.split(' ');
  command = parts[0].toLowerCase().replace(/@.*/, '');
  params = parts.slice(1).join(' ');
} else {
  params = text;
}

const routeMap = {
  '/start': 'start', '/niche': 'set_niche', '/brand': 'set_brand',
  '/research': 'research', '/create': 'create', '/post': 'post',
  '/analytics': 'analytics', '/report': 'report', '/monetize': 'monetize',
  '/trends': 'trends', '/competitors': 'competitors', '/hooks': 'hooks',
  '/hashtags': 'hashtags', '/schedule': 'schedule', '/repurpose': 'repurpose',
  '/health': 'health', '/milestones': 'milestones', '/settings': 'settings',
  '/status': 'status', '/help': 'help'
};

return [{ json: { route: routeMap[command] || 'chat', command, params, chatId, username, firstName, timestamp: new Date().toISOString() } }];

// ============================================
// IMAGE HOSTING — CLOUDINARY INTEGRATION
// Uploads rendered carousel images to Cloudinary
// ============================================

const input = $input.first().json;
const imageBuffer = input.imageBuffer;
const slideNum = input.slideNum || 1;
const carouselId = input.carouselId || Date.now();

const cloudName = process.env.CLOUDINARY_CLOUD_NAME;
const apiKey = process.env.CLOUDINARY_API_KEY;
const apiSecret = process.env.CLOUDINARY_API_SECRET;

if (!cloudName || !apiKey) {
  // Fallback: save locally and use public URL
  const fs = require('fs');
  const path = require('path');
  const dir = '/var/www/carousels';
  try { fs.mkdirSync(dir, { recursive: true }); } catch(e) {}

  const filename = `${carouselId}_slide_${slideNum}.png`;
  const filepath = path.join(dir, filename);

  if (imageBuffer) {
    fs.writeFileSync(filepath, Buffer.from(imageBuffer, 'base64'));
  }

  const publicUrl = `${process.env.PUBLIC_URL || 'http://localhost:8080'}/${filename}`;
  return [{ json: { url: publicUrl, slideNum, carouselId, hosted: 'local' } }];
}

// Upload to Cloudinary
const crypto = require('crypto');
const timestamp = Math.floor(Date.now() / 1000);
const folder = `ig-viral/${carouselId}`;
const publicId = `slide_${slideNum}`;

// Signature for unsigned upload
const signatureStr = `folder=${folder}&public_id=${publicId}&timestamp=${timestamp}${apiSecret}`;
const signature = crypto.createHash('sha1').update(signatureStr).digest('hex');

return [{
  json: {
    uploadUrl: `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`,
    apiKey: apiKey,
    timestamp: timestamp,
    signature: signature,
    folder: folder,
    publicId: publicId,
    imageBuffer: imageBuffer,
    slideNum: slideNum,
    carouselId: carouselId
  }
}];

// ============================================
// FREE AI PROVIDER ROUTER
// Groq -> Gemini -> Ollama -> HuggingFace
// ============================================

const prompt = $input.first().json.prompt || $input.first().json.params || '';
const chatId = $input.first().json.chatId;

const providers = [];

if (process.env.GROQ_API_KEY) {
  providers.push({
    name: 'Groq',
    endpoint: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { 'Authorization': `Bearer ${process.env.GROQ_API_KEY}`, 'Content-Type': 'application/json' },
    body: { model: 'llama3-70b-8192', messages: [{ role: 'system', content: 'You are VIRAL ENGINE, an elite Instagram growth AI.' }, { role: 'user', content: prompt }], temperature: 0.7, max_tokens: 4000 },
    extract: (data) => data.choices?.[0]?.message?.content
  });
}

if (process.env.GEMINI_API_KEY) {
  providers.push({
    name: 'Gemini',
    endpoint: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${process.env.GEMINI_API_KEY}`,
    headers: { 'Content-Type': 'application/json' },
    body: { contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.7, maxOutputTokens: 4000 } },
    extract: (data) => data.candidates?.[0]?.content?.parts?.[0]?.text
  });
}

providers.push({
  name: 'Ollama',
  endpoint: (process.env.OLLAMA_URL || 'http://localhost:11434') + '/api/generate',
  headers: { 'Content-Type': 'application/json' },
  body: { model: process.env.OLLAMA_MODEL || 'llama3', prompt: prompt, stream: false, options: { temperature: 0.7 } },
  extract: (data) => data.response
});

if (process.env.HF_API_KEY) {
  providers.push({
    name: 'HuggingFace',
    endpoint: 'https://api-inference.huggingface.co/models/meta-llama/Meta-Llama-3-8B-Instruct',
    headers: { 'Authorization': `Bearer ${process.env.HF_API_KEY}`, 'Content-Type': 'application/json' },
    body: { inputs: prompt, parameters: { temperature: 0.7, max_new_tokens: 2000 } },
    extract: (data) => Array.isArray(data) ? data[0]?.generated_text : data.generated_text
  });
}

return [{ json: { providers, prompt, chatId, currentProvider: 0 } }];

const input = $input.first().json;
const providers = input.providers;
const idx = input.currentProvider || 0;
const provider = providers[idx];

if (!provider) return [{ json: { success: false, error: 'All AI providers failed', chatId: input.chatId } }];

return [{ json: { url: provider.endpoint, method: 'POST', headers: provider.headers, body: provider.body, providerName: provider.name, providerIndex: idx, providers, prompt: input.prompt, chatId: input.chatId } }];

const response = $input.first().json;
const request = $('AI Executor Prep').first().json;
let result = null;
let success = false;

try {
  const provider = request.providers[request.providerIndex];
  result = provider.extract(response);
  success = !!result;
} catch (e) {}

if (!success && request.providerIndex < request.providers.length - 1) {
  return [{ json: { ...request, currentProvider: request.providerIndex + 1, retry: true } }];
}

return [{ json: { success, result: result || 'AI generation failed.', provider: request.providers[request.providerIndex]?.name, chatId: request.chatId, prompt: request.prompt } }];

// ============================================
// FULL RESEARCH ENGINE
// Web search + Browser scraping across platforms
// ============================================

const input = $input.first().json;
const niche = input.params || input.niche || '';
const chatId = input.chatId;

if (!niche || niche.length < 2) {
  return [{ json: { error: true, chatId, message: 'Specify a niche. Example: /niche fitness for women over 30' } }];
}

const queries = [
  // Core research
  { q: `${niche} instagram carousel viral examples 2024 2025`, platform: 'web', topic: 'viral_examples' },
  { q: `${niche} content ideas that get engagement`, platform: 'web', topic: 'content_ideas' },
  { q: `${niche} target audience demographics psychology`, platform: 'web', topic: 'audience_psychology' },
