  { q: `${niche} rising hashtags instagram`, platform: 'web', topic: 'rising_hashtags' },

  // Platform-specific
  { q: `site:reddit.com ${niche} tips advice community`, platform: 'reddit', topic: 'community_insights' },
  { q: `site:twitter.com OR site:x.com ${niche} trending viral`, platform: 'twitter', topic: 'twitter_trends' },
  { q: `site:tiktok.com ${niche} viral trends`, platform: 'tiktok', topic: 'tiktok_trends' },
  { q: `site:pinterest.com ${niche} ideas inspiration`, platform: 'pinterest', topic: 'pinterest_ideas' },
  { q: `site:youtube.com ${niche} tutorial tips popular`, platform: 'youtube', topic: 'youtube_content' },

  // Strategy
  { q: `${niche} best time to post instagram`, platform: 'web', topic: 'posting_times' },
  { q: `${niche} instagram growth strategy case study`, platform: 'web', topic: 'growth_strategy' },
  { q: `${niche} content pillar ideas instagram`, platform: 'web', topic: 'content_pillars' },
  { q: `${niche} instagram algorithm tips 2024`, platform: 'web', topic: 'algorithm_tips' },

  // Monetization
  { q: `${niche} digital products to sell instagram`, platform: 'web', topic: 'monetization_products' },
