];

return targets.map((t, i) => ({ json: { ...t, niche, chatId, index: i } }));

const input = $input.first().json;
const body = input.body || '';
const platform = input.platform;
const topic = input.topic;
const niche = input.niche;
const chatId = input.chatId;

let extracted = '';
try {
  if (platform === 'reddit') {
    const data = typeof body === 'string' ? JSON.parse(body) : body;
    const posts = data?.data?.children || [];
    extracted = posts.slice(0, 15).map(p => {
      const d = p.data;
      return `Title: ${d.title}\nScore: ${d.score}\nComments: ${d.num_comments}\nSubreddit: r/${d.subreddit}\nURL: https://reddit.com${d.permalink}`;
    }).join('\n---\n');
  } else {
    const text = typeof body === 'string' ? body : '';
    const titleMatch = text.match(/<title[^>]*>([^<]+)<\/title>/i);
    const metaDesc = text.match(/<meta[^>]*name="description"[^>]*content="([^"]+)"/i);
    const ogDesc = text.match(/<meta[^>]*property="og:description"[^>]*content="([^"]+)"/i);
    const cleanText = text.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 3000);
    extracted = `Platform: ${platform}\nTopic: ${topic}\n`;
    if (titleMatch) extracted += `Title: ${titleMatch[1]}\n`;
    if (metaDesc) extracted += `Description: ${metaDesc[1]}\n`;
    if (ogDesc) extracted += `OG: ${ogDesc[1]}\n`;
    extracted += `Content: ${cleanText.substring(0, 1500)}`;
  }
} catch (e) {
  extracted = `Platform: ${platform} — Parse error: ${e.message}`;
}

return [{ json: { platform, topic, data: extracted, niche, chatId } }];

// ============================================
// RESEARCH AGGREGATOR + KNOWLEDGE BASE BUILDER
// ============================================

const allResults = $input.all();
const niche = allResults[0]?.json?.niche || 'unknown';
const chatId = allResults[0]?.json?.chatId;

const byTopic = {};
const byPlatform = {};

allResults.forEach(r => {
  const d = r.json;
  if (!d.data && !d.query) return;
  if (!byTopic[d.topic]) byTopic[d.topic] = [];
  byTopic[d.topic].push(d.data || '');
  if (!byPlatform[d.platform]) byPlatform[d.platform] = [];
  byPlatform[d.platform].push(d.data || '');
});

let kb = `# NICHE KNOWLEDGE BASE: ${niche}\nGenerated: ${new Date().toISOString()}\nSources: ${allResults.length} queries across ${Object.keys(byPlatform).length} platforms\n\n`;

for (const [topic, data] of Object.entries(byTopic)) {
  kb += `## ${topic.replace(/_/g, ' ').toUpperCase()}\n`;
  kb += data.filter(d => d && d.length > 10).join('\n---\n').substring(0, 2000);
  kb += `\n\n`;
}

// Extract hook patterns
const hookPatterns = [];
const hookData = byTopic['hooks'] || [];
hookData.forEach(h => {
  const matches = h.match(/(?:hook|headline|title)[:\s]+([^\n]{10,100})/gi);
  if (matches) hookPatterns.push(...matches.slice(0, 5));
});

// Extract hashtag data
const hashtags = [];
const hashData = byTopic['hashtags'] || [];
hashData.forEach(h => {
  const matches = h.match(/#[a-zA-Z0-9_]+/g);
  if (matches) hashtags.push(...matches.slice(0, 10));
});

return [{ json: {
  niche, knowledgeBase: kb, chatId,
  topicsResearched: Object.keys(byTopic).length,
  platformsScraped: Object.keys(byPlatform).length,
  totalSources: allResults.length,
  hookPatterns: hookPatterns.slice(0, 20),
  hashtags: [...new Set(hashtags)].slice(0, 30),
  timestamp: new Date().toISOString()
} }];

// ============================================
// TREND JACKING ENGINE
// Monitors trending topics and adapts content
// ============================================

const input = $input.first().json;
const niche = input.params || input.niche || '';
const chatId = input.chatId;

const prompt = `You are VIRAL ENGINE's trend detection system.

NICHE: ${niche}

Research current trending topics, viral formats, and cultural moments that could be adapted to this niche.

Identify:
1. Trending topics that relate to this niche
2. Viral carousel formats that could be adapted
3. Current memes or cultural moments
4. Seasonal opportunities
5. Rising hashtags

For each trend, explain:
- What it is
- Why it's trending
- How to adapt it to this niche
- Example hook using this trend

Output as a clear, actionable list.`;

return [{ json: { prompt, chatId } }];

