Make them SPECIFIC to this niche. Not generic.`;

return [{ json: { prompt, chatId } }];

// ============================================
// HTML CAROUSEL RENDERER
// Converts carousel JSON to beautiful HTML
// ============================================

const input = $input.first().json;
let carousel;

try {
  const raw = input.result || input.response || input.body || '';
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const jsonMatch = text.match(/\{[\s\S]*"slides"[\s\S]*\}/);
  carousel = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
} catch (e) { carousel = null; }

if (!carousel || !carousel.slides) {
  carousel = {
    slides: [
      { number: 1, type: 'hook', headline: 'Stop Scrolling', subtext: 'This changes everything', bg_color: '#0a0a0a', text_color: '#ffffff' },
      { number: 2, type: 'content', headline: 'The Problem', body: 'Most people get this wrong', bg_color: '#1a1a2e', text_color: '#ffffff' },
      { number: 3, type: 'content', headline: 'The Truth', body: 'Here is what actually works', bg_color: '#16213e', text_color: '#ffffff' },
      { number: 4, type: 'content', headline: 'Step 1', body: 'Start with this', bg_color: '#0f3460', text_color: '#ffffff' },
      { number: 5, type: 'content', headline: 'Step 2', body: 'Then do this', bg_color: '#533483', text_color: '#ffffff' },
      { number: 6, type: 'cta', headline: 'Save This', body: 'Follow for more', bg_color: '#e94560', text_color: '#ffffff' }
    ],
    caption: 'Check out this post!', hashtags: ['#tips', '#growth'], hook_type: 'curiosity', content_pillar: 'educational'
  };
}

const chatId = input.chatId;
const total = carousel.slides.length;

const slidesHtml = carousel.slides.map(s => {
  const bg = s.bg_color || '#0a0a0a';
  const tc = s.text_color || '#ffffff';
  const isHook = s.type === 'hook';
  const isCta = s.type === 'cta';
  const h = (s.headline || '').replace(/</g, '&lt;');
  const b = (s.body || s.subtext || '').replace(/</g, '&lt;');

  return `<div class="slide" style="width:1080px;height:1080px;background:${bg};display:flex;flex-direction:column;justify-content:center;align-items:center;padding:80px;box-sizing:border-box;font-family:'Inter','Helvetica Neue',Arial,sans-serif;position:relative;overflow:hidden;">
<div style="position:absolute;top:-60px;right:-60px;width:220px;height:220px;border-radius:50%;border:1px solid rgba(255,255,255,0.06);"></div>
<div style="position:absolute;bottom:-80px;left:-80px;width:300px;height:300px;border-radius:50%;border:1px solid rgba(255,255,255,0.04);"></div>
<div style="position:absolute;top:40px;right:50px;font-size:14px;color:rgba(255,255,255,0.25);font-weight:500;letter-spacing:3px;">${String(s.number).padStart(2,'0')} / ${String(total).padStart(2,'0')}</div>
<div style="text-align:center;max-width:880px;z-index:1;">
${isHook ? '<div style="width:50px;height:4px;background:rgba(255,255,255,0.3);margin:0 auto 30px;"></div>' : ''}
<h1 style="font-size:${isHook?'68px':'52px'};font-weight:${isHook?'900':'700'};color:${tc};margin:0 0 24px;line-height:1.1;letter-spacing:-2px;${isHook?'text-transform:uppercase;':''}">${h}</h1>
${b?`<p style="font-size:22px;color:rgba(255,255,255,0.7);margin:0;line-height:1.7;">${b}</p>`:''}
${isCta?`<div style="margin-top:40px;padding:18px 48px;border:2px solid rgba(255,255,255,0.3);border-radius:50px;display:inline-block;font-size:18px;font-weight:600;color:${tc};letter-spacing:1px;">${b}</div>`:''}
</div></div>`;
}).join('');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{background:#000}</style></head><body>${slidesHtml}</body></html>`;

return [{ json: { html, carousel, chatId, slideCount: total } }];

const input = $input.first().json;
const carousel = input.carousel;
const chatId = input.chatId;

let msg = `NEW CAROUSEL CREATED

`;
msg += `Hook: ${carousel.slides[0]?.headline || 'N/A'}
`;
msg += `Hook Type: ${carousel.hook_type || 'N/A'}
`;
msg += `Pillar: ${carousel.content_pillar || 'N/A'}
`;
msg += `Slides: ${carousel.slides.length}
`;
msg += `Best Time: ${carousel.best_posting_time || 'Now'}
`;
msg += `Predicted: ${carousel.predicted_engagement || 'Strong'}

`;

if (carousel.hook_analysis) msg += `Hook Analysis: ${carousel.hook_analysis}
`;
if (carousel.psychology_used) msg += `Psychology: ${carousel.psychology_used}
`;
if (carousel.save_optimization) msg += `Save Optimization: ${carousel.save_optimization}
`;
